+
+/**
+ * Configuration for attention mechanisms
+ */
+export interface AttentionConfig {
+  /** Number of attention heads */
+  numHeads: number;
+  /** Dimension of each head */
+  headDim: number;
+  /** Total embedding dimension (usually numHeads * headDim) */
