+  /** Execution time in milliseconds */
+  executionTimeMs: number;
+  /** Which mechanism was used */
+  mechanism: 'multi-head' | 'flash' | 'linear' | 'hyperbolic' | 'moe' | 'sparse' | 'partitioned';
